export const lessonEnPb: Record<string, string> = {
  'pb-1.s0.body': 'A prompt is the input you use to steer a language model: question, task, context, and constraints in one package. Good prompts reduce guesswork and produce more reproducible results. Think of the model as a conversation partner that only sees what you write - nothing is implicit.',
  'pb-1.s0.title': 'Prompt = instruction for the model',
  'pb-1.s1.explanation': 'A prompt bundles everything the model needs to know and do, not just a loose question.',
  'pb-1.s1.opt0': 'A random question for the internet.',
  'pb-1.s1.opt1': 'A structured instruction with context, a task, and optional constraints.',
  'pb-1.s1.opt2': 'Only the name of the desired output format.',
  'pb-1.s1.question': 'What describes a prompt most accurately?',
  'pb-1.s2.explanation': 'Clear instructions leave less room for interpretation, so you need fewer follow-up corrections.',
  'pb-1.s2.opt0': 'Because models always guess the best answer without clear instructions.',
  'pb-1.s2.opt1': 'Because precise prompts create less rework and fewer hallucinations.',
  'pb-1.s2.opt2': 'Because longer prompts automatically get better scores in the Prompt Lab.',
  'pb-1.s2.question': 'Why is intentional prompting worthwhile?',
  'pb-1.title': 'What is a prompt?',
  'pb-2.s0.body': 'Phrase tasks as concrete instructions: "Analyze...", "List...", "Compare...". Avoid vague words like "something", "good", or "better" when there is no measurable criterion. A clear instruction names the action and the expected outcome.',
  'pb-2.s0.title': 'Clarity beats politeness',
  'pb-2.s1.blank0': 'Improve',
  'pb-2.s1.blank1': 'Shorten',
  'pb-2.s1.blank2': 'Make',
  'pb-2.s1.explanation': 'The action (shorten), limit (120 words), and content (three core arguments) are clearly specified.',
  'pb-2.s1.opt0': 'Do something nice with the text.',
  'pb-2.s1.prefix': 'Which verb starts the clearest instruction? Complete: "',
  'pb-2.s1.suffix': ' the text to no more than 120 words and keep the three core arguments."',
  'pb-2.s1.opt1': 'Shorten the text to no more than 120 words and keep the three core arguments.',
  'pb-2.s1.opt2': 'Improve the text if you have time.',
  'pb-2.s1.question': 'Which instruction is the clearest?',
  'pb-2.s2.explanation': 'Without criteria for what counts as "good," the model decides by its own standard.',
  'pb-2.s2.opt0': 'The word "report" is too technical.',
  'pb-2.s2.opt1': '"Good" is not measurable - length, tone, and structure are missing.',
  'pb-2.s2.opt2': 'Reports are not allowed in prompts.',
  'pb-2.s2.question': 'What makes "Write a good report" problematic?',
  'pb-2.title': 'Clear instructions',
  'pb-3.s0.body': 'A prompt without a clear goal forces the model to guess. The more precisely you describe the desired outcome, the closer the first answer will be to what you want. State the goal as an expected result, not as a vague direction.',
  'pb-3.s0.title': 'Why goals matter',
  'pb-3.s1.explanation': 'The second version defines format (3 paragraphs), content (benefits, features, CTA), and audience, so the model does not have to guess.',
  'pb-3.s1.opt0': 'Write something about our new product.',
  'pb-3.s1.opt1': 'Create a product description with 3 paragraphs: benefits, features, call to action - the target audience is procurement managers.',
  'pb-3.s1.opt2': 'Write a good website text, and it can be a bit longer.',
  'pb-3.s1.question': 'Which goal definition is the most precise?',
  'pb-3.s2.explanation': 'Without target length, audience, and format, the model decides for itself and rarely matches your expectation.',
  'pb-3.s2.opt0': 'Nothing - the prompt is complete.',
  'pb-3.s2.opt1': 'Target length, audience, and format of the summary.',
  'pb-3.s2.opt2': 'A friendly greeting to the model.',
  'pb-3.s2.question': 'What is missing in this prompt? "Summarize the report."',
  'pb-3.title': 'Goal definition',
  'pb-4.s0.body': 'Tell the model what form the answer should take: bullet list, table, JSON, prose, email. Format instructions keep you from having to restructure the content afterward. The more specific the schema, the less editing you need later.',
  'pb-4.s0.title': 'Set the format early',
  'pb-4.s1.explanation': 'The number, structure (bullet points), and word limit per point are clearly defined.',
  'pb-4.s1.opt0': 'Reply in some kind of clear way.',
  'pb-4.s1.opt1': 'Return 5 bullet points with no more than 15 words each.',
  'pb-4.s1.opt2': 'Write as much as needed; the format does not matter.',
  'pb-4.s1.question': 'Which format instruction is the most useful?',
  'pb-4.s2.explanation': 'Structured formats make automation and comparison across runs easier.',
  'pb-4.s2.opt0': 'Only when you are writing code - otherwise never.',
  'pb-4.s2.opt1': 'When the answer needs to be processed or parsed by a machine.',
  'pb-4.s2.opt2': 'JSON is always better than prose.',
  'pb-4.s2.question': 'When is an explicit output format like JSON worthwhile?',
  'pb-4.title': 'Format instructions',
  'pb-5.s0.body': 'One or two examples of input and desired output calibrate the model faster than long rules. Examples should be representative and reflect the style, tone, and format you want. Place them directly before the actual task.',
  'pb-5.s0.title': 'Few-shot: show instead of explain',
  'pb-5.s1.explanation': 'Examples demonstrate the target pattern, but they do not replace a clear task and constraints.',
  'pb-5.s1.opt0': 'It is as long as possible and includes all edge cases.',
  'pb-5.s1.opt1': 'It shows the input and target output in the desired style and format.',
  'pb-5.s1.opt2': 'It completely replaces every written instruction.',
  'pb-5.s1.question': 'What makes a good prompt example?',
  'pb-5.s2.explanation': 'Concrete example pairs anchor length, style, and naming patterns better than abstract appeals.',
  'pb-5.s2.opt0': '"Invent creative names."',
  'pb-5.s2.opt1': 'Two example pairs (briefing -> name) plus the new task.',
  'pb-5.s2.opt2': '"Be creative, but not too creative."',
  'pb-5.s2.question': 'You want short product names in the style of "NovaLite." What helps the most?',
  'pb-5.title': 'Using examples',
  'pb-6.s0.body': 'Negative instructions limit unwanted behavior: no technical jargon, no emojis, no marketing hype. They work best together with positive guidance - otherwise the model does not know what to do instead. Phrase prohibitions concretely, not vaguely.',
  'pb-6.s0.title': 'State what should not happen',
  'pb-6.s1.explanation': 'Specific prohibitions are testable; vague warnings are not.',
  'pb-6.s1.opt0': 'Do not do anything wrong.',
  'pb-6.s1.opt1': 'Do not use emojis, exclamation marks, or superlatives.',
  'pb-6.s1.opt2': 'Please be careful.',
  'pb-6.s1.question': 'Which negative instruction is most effective?',
  'pb-6.s2.explanation': 'Without a positive target format, it is unclear which structure is expected instead.',
  'pb-6.s2.opt0': 'A positive alternative, for example prose in 2 paragraphs.',
  'pb-6.s2.opt1': 'More negative rules.',
  'pb-6.s2.opt2': 'An example of a bad answer.',
  'pb-6.s2.question': 'What is missing from a purely negative list like "No bullet points, no JSON"?',
  'pb-6.title': 'Negative instructions',
  'pb-7.s0.body': 'Longer prompts are not automatically better. Every sentence should add information or a constraint. Redundancy and repetition blur priorities. For complex tasks, it is better to use sections than to emphasize everything multiple times.',
  'pb-7.s0.title': 'As long as necessary, as short as possible',
  'pb-7.s1.explanation': 'Clear sections and numbered constraints are easier to follow than repetition.',
  'pb-7.s1.opt0': 'The request "Be precise" repeated three times without further detail.',
  'pb-7.s1.opt1': 'Context in 2 sentences, the task in 1 sentence, and 3 numbered constraints.',
  'pb-7.s1.opt2': 'A 400-word paragraph without headings.',
  'pb-7.s1.question': 'Which prompt is structured more efficiently?',
  'pb-7.s2.explanation': 'Length is justified by added value: context, examples, precise rules - not filler.',
  'pb-7.s2.opt0': 'Always - the longer it is, the more professional it looks.',
  'pb-7.s2.opt1': 'When a lot of context, examples, or consistent rules are necessary.',
  'pb-7.s2.opt2': 'Only for models without a context window.',
  'pb-7.s2.question': 'When is a longer prompt worthwhile?',
  'pb-7.title': 'Prompt length',
  'pb-8.s0.body': 'In this final project, you combine a clear instruction, goal definition, format, optional examples, and negative rules. A complete fundamentals prompt reads like a short briefing sheet: context -> task -> format -> constraints -> prohibitions.',
  'pb-8.s0.title': 'Bring it all together',
  'pb-8.s1.explanation': 'Context, task, length limit, structure, and negative rules are combined in one compact prompt.',
  'pb-8.s1.opt0': 'Write a launch post for our product.',
  'pb-8.s1.opt1': 'Context: B2B SaaS for HR. Task: LinkedIn post (max. 150 words). Format: hook, benefits, CTA. No emojis, no hype.',
  'pb-8.s1.opt2': 'LinkedIn post, professional, please make it good.',
  'pb-8.s1.question': 'Which prompt covers the fundamentals most completely?',
  'pb-8.s2.explanation': 'Without context and format, the answer stays too generic - that is exactly what you are practicing to avoid in this path.',
  'pb-8.s2.opt0': 'A request for politeness.',
  'pb-8.s2.opt1': 'A project description, risk categories, and a format (for example a table with likelihood).',
  'pb-8.s2.opt2': 'More exclamation marks for urgency.',
  'pb-8.s2.question': 'What would you add to Prompt B first? B: "List 5 risks for our project."',
  'pb-8.title': 'Final project',
  'pb-9.s0.body': 'A model can only follow what\'s actually written in the prompt – not what you meant. Vague words like "good", "short", or "professional" leave too much room for interpretation. The more concrete you are, the more predictable the result.',
  'pb-9.s0.title': 'Why Precision Matters',
  'pb-9.s1.explanation': '"Short" is relative and gets interpreted differently by every model. A concrete number ("maximum 80 words") leaves no room for interpretation – the result becomes reliably more predictable.',
  'pb-9.s1.statement': '"Write a short text" is just as precise as "Write a text with a maximum of 80 words".',
  'pb-9.s2.explanation': 'The second version defines length (3 sentences), audience (12-year-old), and a clear constraint (no technical terms) – "simply" alone leaves open what "simple" actually means.',
  'pb-9.s2.opt0': 'Explain photosynthesis to me simply.',
  'pb-9.s2.opt1': 'Explain photosynthesis in 3 sentences, understandable for a 12-year-old, without technical terms.',
  'pb-9.s2.question': 'Which prompt is more precisely formulated?',
  'pb-9.title': 'Vague vs. Precise Wording',
  'pb-10.s0.body': 'When a prompt asks for five different things at once, the quality of each individual answer drops. Models often handle multiple instructions unevenly – usually the last-mentioned task gets the most thorough treatment, the rest only superficially.',
  'pb-10.s0.title': 'Avoiding Overloaded Prompts',
  'pb-10.s1.blank0': 'several separate prompts',
  'pb-10.s1.blank1': 'even more sub-tasks',
  'pb-10.s1.blank2': 'a single, longer sentence',
  'pb-10.s1.explanation': 'Separate prompts (or at least clearly numbered individual steps) prevent tasks from getting lost. More sub-tasks or a longer sentence would worsen the problem, not solve it.',
  'pb-10.s1.prefix': 'Instead of "Summarize the text, translate it, and also write a title", it\'s better to split the task into:',
  'pb-10.s1.suffix': ' – this way each sub-task gets the model\'s full attention.',
  'pb-10.s2.explanation': 'Going sequentially ensures the summary can be checked first before it\'s translated – errors in step 1 otherwise propagate unnoticed into step 2.',
  'pb-10.s2.opt0': 'Ask for both in one prompt to save time',
  'pb-10.s2.opt1': 'Two separate prompts in sequence, first summary, then translation of the summary',
  'pb-10.s2.question': 'You need both a summary AND a translation of a text. What\'s the most reliable approach?',
  'pb-10.title': 'One Task at a Time',
  'pb-11.s0.body': 'Without a specified audience, the model picks a neutral middle ground – often neither precise enough for experts nor understandable enough for laypeople. An explicit audience statement steers word choice, technical depth, and tone all at once.',
  'pb-11.s0.title': 'Who Is the Model Writing For?',
  'pb-11.s1.explanation': 'The audience specification is a swappable building block in the prompt – the rest (topic, format, length) stays stable. This makes the prompt reusable across different audiences.',
  'pb-11.s1.opt0': 'Only the audience specification, the rest of the prompt stays the same',
  'pb-11.s1.opt1': 'Rewrite the entire prompt independently for each audience',
  'pb-11.s1.question': 'You want the same fact explained once for children and once for experts. What do you change in the prompt?',
  'pb-11.s2.explanation': '"Beginner" is relative to the topic – a programming beginner and a cooking beginner need completely different levels of explanation depth. Better: name concrete prior knowledge, e.g. "someone who has never coded before".',
  'pb-11.s2.statement': '"Explain it to me like a beginner" is a sufficiently precise audience specification.',
  'pb-11.title': 'Specifying Your Audience',
  'pb-12.s0.body': 'A typical beginner prompt often has several weaknesses at once: unclear goal, missing format, no length guidance. Fixing these weaknesses sensibly follows an order – not everything at once, but from most important to smallest.',
  'pb-12.s0.title': 'Fixing a Weak Prompt',
  'pb-12.s1.explanation': 'An unclear goal makes any further refinement worthless – hence it comes first. Context and format are structurally more important than finishing touches like tone, which comes last.',
  'pb-12.s1.instruction': 'Put the steps for improving a weak prompt into the sensible order.',
  'pb-12.s1.item0': 'Define a clear, concrete goal',
  'pb-12.s1.item1': 'Add necessary context',
  'pb-12.s1.item2': 'Specify the output format',
  'pb-12.s1.item3': 'Add finishing touches like tone or length',
  'pb-12.s2.explanation': 'Beginners often underestimate how much needs to be said explicitly – they mistakenly assume the model "already knows what\'s meant". Too many details is a rarer problem than too few.',
  'pb-12.s2.opt0': 'Providing too many details and constraints',
  'pb-12.s2.opt1': 'Assuming the model already knows the unspoken context',
  'pb-12.s2.question': 'Which mistake is most common among beginners?',
  'pb-12.title': 'Common Beginner Mistakes',
  'pb-13.s0.body': 'This lesson brings together what you\'ve learned so far: precision, one task per prompt, audience specification. A truly good prompt combines several of these principles at once, not just one.',
  'pb-13.s0.title': 'Putting It All Together',
  'pb-13.s1.explanation': 'Option 2 defines audience (children 6-8), length (4 sentences), and a single clear topic. Option 1 is vague, option 3 overloads the prompt with multiple tasks at once.',
  'pb-13.s1.opt0': 'Write something good about dogs.',
  'pb-13.s1.opt1': 'Write a 4-sentence paragraph for a children\'s book audience (ages 6-8) about why dogs are good pets.',
  'pb-13.s1.opt2': 'Explain everything about dogs, cats, and birds as pets, with pros and cons, and also write a poem about it.',
  'pb-13.s1.question': 'Which prompt combines the most of the principles learned so far?',
  'pb-13.s2.explanation': 'Precision and task focus are two independent principles. A prompt can be precise in every single detail and still fail because it asks for too much at once.',
  'pb-13.s2.statement': 'A prompt can still fail despite perfect precision if it asks for multiple tasks at once.',
  'pb-13.title': 'Recognizing Good vs. Bad Prompts',
  'pb-14.s0.body': 'A prompt usually consists of several building blocks: context, the actual task, format, constraints. A sensible base order is context → task → format → constraints – this builds the instruction up logically instead of scattering information randomly.',
  'pb-14.s0.title': 'What Comes First?',
  'pb-14.s1.explanation': 'Context first gives the model the foundation to properly interpret the task. Format and constraints are fine-tuning and therefore come after.',
  'pb-14.s1.instruction': 'Put the building blocks of a prompt into a logical base order.',
  'pb-14.s1.item0': 'Background information (context)',
  'pb-14.s1.item1': 'The actual task',
  'pb-14.s1.item2': 'Desired format',
  'pb-14.s1.item3': 'Constraints (e.g. length, tone)',
  'pb-14.s2.explanation': 'The order can very much influence what the model weighs more heavily – especially with long prompts. A logical structure reduces the risk that important details get lost.',
  'pb-14.s2.statement': 'The order of prompt components never influences the result.',
  'pb-14.title': 'Order of Prompt Components',
  'pb-15.s0.body': 'A widespread myth: politeness phrases would improve answer quality. In reality, what almost exclusively matters is the substantive clarity of the instruction – a direct, clear command works just as well as a polite request.',
  'pb-15.s0.title': 'Do I Have to Say "Please"?',
  'pb-15.s1.explanation': 'Both lead to comparable results, as long as the actual task is clear. The politeness phrases add length without adding substantive value to the result.',
  'pb-15.s1.statement': '"Could you please kindly help me summarize a text?" leads to a better summary than "Summarize this text."',
  'pb-15.s2.explanation': 'The practical advantage is on your side as the author: direct prompts are easier to maintain and reuse, not a guaranteed model speed benefit.',
  'pb-15.s2.opt0': 'Shorter prompts are easier to read, review, and reuse',
  'pb-15.s2.opt1': 'The model fundamentally responds faster to direct prompts',
  'pb-15.s2.question': 'What\'s the actual advantage of formulating prompts directly rather than elaborately?',
  'pb-15.title': 'Politeness vs. Directness',
  'pb-16.s0.body': 'Models tend to give a confident-sounding answer even when uncertain. You can explicitly counteract this by allowing or even requiring the prompt to openly state uncertainty instead of guessing.',
  'pb-16.s0.title': 'Better "I Don\'t Know" Than a Wrong Answer',
  'pb-16.s1.explanation': 'The second phrasing explicitly permits the model to communicate uncertainty – this lowers the likelihood of a confidently phrased but wrong answer.',
  'pb-16.s1.opt0': '"Always answer, even if you\'re unsure."',
  'pb-16.s1.opt1': '"If you\'re not sure, say so explicitly instead of guessing."',
  'pb-16.s1.question': 'Which addition to the prompt reduces the risk of a fabricated, wrong answer?',
  'pb-16.s2.explanation': 'It\'s a risk reduction, not a guarantee. For truly critical facts, external verification remains necessary.',
  'pb-16.s2.statement': 'Explicitly allowing "I don\'t know" in the prompt can help, but doesn\'t guarantee correct answers.',
  'pb-16.title': 'Handling Uncertainty',
  'pb-17.s0.body': 'A single example in the prompt can lock the model too strongly onto its specific traits – such as length, tone, or structure – even if those traits weren\'t actually intended. Multiple, varied examples show the model what should actually stay constant.',
  'pb-17.s0.title': 'The Risk of a Single Example',
  'pb-17.s1.explanation': 'Models infer implicit patterns from examples, including unintended ones like length. A second, shorter example would show that length isn\'t the relevant pattern here.',
  'pb-17.s1.opt0': 'The model adopts the length as a perceived requirement, even though that wasn\'t intended',
  'pb-17.s1.opt1': 'The model completely ignores the example\'s length',
  'pb-17.s1.question': 'You give a single example of a product description that happens to be very long. What likely happens?',
  'pb-17.s2.blank0': 'add a second example with a different length',
  'pb-17.s2.blank1': 'make the single example even longer',
  'pb-17.s2.explanation': 'Variation between multiple examples shows the model which trait is constant (the actual pattern) and which is incidental. A longer single example would worsen the problem.',
  'pb-17.s2.prefix': 'To show that an example\'s length isn\'t meant as a requirement, it helps to ',
  'pb-17.s2.suffix': ' – this way the model recognizes which pattern truly applies across examples.',
  'pb-17.title': 'One Example Isn\'t Always Enough',
  'pb-18.s0.body': 'Instead of writing a new prompt for every similar task, you can use placeholders like {{topic}} or {{name}}. This creates a template you can reuse for many similar cases without having to rethink the underlying structure every time.',
  'pb-18.s0.title': 'Placeholders Instead of Rewriting',
  'pb-18.s1.explanation': 'A template pays off once a task structure repeats – e.g. writing product descriptions for different products over and over. For a genuine one-off task, a template offers no advantage.',
  'pb-18.s1.opt0': 'For a one-time, very specific task',
  'pb-18.s1.opt1': 'For a recurring task with a stable structure but changing details',
  'pb-18.s1.question': 'When is a prompt template with placeholders most worthwhile?',
  'pb-18.s2.blank0': 'interchangeable placeholders',
  'pb-18.s2.blank1': 'fixed, unchangeable text components',
  'pb-18.s2.explanation': 'Placeholders exist precisely to be swapped out with each use – that\'s the whole point of a reusable template.',
  'pb-18.s2.prefix': 'In the template "Write a product description for {{product_name}} in {{count}} sentences", {{product_name}} and {{count}} act as ',
  'pb-18.s2.suffix': ', which get filled in anew each time the template is used.',
  'pb-18.title': 'Prompts as Reusable Templates',
  'pb-19.s0.body': 'A leading question already embeds a judgment in its phrasing, e.g. "Why is X clearly the best solution?" The model often adopts this judgment uncritically instead of questioning it – the result becomes one-sided.',
  'pb-19.s0.title': 'When the Question Presupposes the Answer',
  'pb-19.s1.explanation': 'The second phrasing doesn\'t presuppose an outcome and asks for a balanced view. The first already establishes that A is better before any argument has been made.',
  'pb-19.s1.opt0': 'Why is Option A clearly better than Option B?',
  'pb-19.s1.opt1': 'Compare Option A and Option B based on pros and cons.',
  'pb-19.s1.question': 'Which phrasing is free of leading bias?',
  'pb-19.s2.explanation': 'A clear direction isn\'t the same as a reliable, unbiased answer. Leading questions tend to produce one-sided rather than reliable results.',
  'pb-19.s2.statement': 'A leading question fundamentally delivers more reliable results because it gives the model a clear direction.',
  'pb-19.title': 'Avoiding Leading Questions',
  'pb-20.s0.body': 'If you want to compare data or present it clearly, it helps to name the output format concretely: "as a table with columns X, Y, Z" or "as a numbered list". Without this, the model decides on its own, which often results in prose where a table would be clearer.',
  'pb-20.s0.title': 'Explicitly Requesting Structured Output',
  'pb-20.s1.explanation': 'The explicit table structure with named columns makes the result directly comparable. The second prompt leaves format and structure to chance.',
  'pb-20.s1.opt0': '"Present the result as a table with columns Price, Battery Life, Camera."',
  'pb-20.s1.opt1': '"Compare the three smartphones."',
  'pb-20.s1.question': 'You want to compare three smartphones by price, battery life, and camera. Which prompt addition is most helpful?',
  'pb-20.s2.explanation': 'The model makes a plausible but not guaranteed-optimal choice. Explicit format specifications remove this risk from the equation.',
  'pb-20.s2.statement': 'Without a format specification, the model always automatically chooses the most sensible presentation for comparisons.',
  'pb-20.title': 'Requesting Tables and Lists',
  'pb-21.s0.body': 'In very long prompts, instructions in the middle can sometimes get less attention than those at the beginning or end. The single most important instruction therefore belongs at one of these two edge positions, not buried somewhere in the middle of running text.',
  'pb-21.s0.title': 'Position Affects Weighting',
  'pb-21.s1.explanation': 'Edge positions tend to receive more attention than the middle of a long text – this holds for prompts just as it does for many other text forms.',
  'pb-21.s1.opt0': 'Somewhere in the middle, among the other details',
  'pb-21.s1.opt1': 'At the beginning or the end, clearly set apart from the other details',
  'pb-21.s1.question': 'You have a long prompt with many details. Where do you most sensibly place the single most important instruction?',
  'pb-21.s2.explanation': 'The position problem mainly arises with long, detail-rich prompts. In short prompts, everything is close together and easily grasped anyway.',
  'pb-21.s2.statement': 'In short prompts (1-2 sentences), the position of instructions plays practically no relevant role.',
  'pb-21.title': 'Important Things First or Last?',
  'pb-22.s0.body': 'A long prompt often feels more thorough, but it isn\'t automatically so. What matters is whether every additional word actually delivers new, relevant information – not the sheer word count.',
  'pb-22.s0.title': 'More Words in the Prompt ≠ Better Result',
  'pb-22.s1.explanation': 'If the 30 words precisely contain all the relevant information, that prompt can outperform a 200-word prompt full of redundancy. Relevance beats length.',
  'pb-22.s1.statement': 'A 200-word prompt fundamentally delivers better results than a 30-word one.',
  'pb-22.s2.explanation': 'Sheer sentence count isn\'t a quality indicator. Repeated information without new value is the real signal of unnecessary length.',
  'pb-22.s2.opt0': 'Words or sentences repeat the same information multiple times, differently phrased',
  'pb-22.s2.opt1': 'The prompt contains more than three sentences',
  'pb-22.s2.question': 'How do you recognize that a prompt is unnecessarily bloated?',
  'pb-22.title': 'Length Isn\'t the Same as Quality',
  'pb-23.s0.body': 'You\'ve now learned many individual principles: precision, task focus, audience, order, allowing uncertainty, format specification. A good routine is to briefly run through these points mentally before sending an important prompt.',
  'pb-23.s0.title': 'All Principles in One Routine',
  'pb-23.s1.explanation': 'This order mirrors importance: without a clear goal, everything else is moot; tone and audience are finishing touches at the end.',
  'pb-23.s1.instruction': 'Put this checklist into a sensible check order before sending a prompt.',
  'pb-23.s1.item0': 'Is the goal clear and singular (not multiple tasks mixed)?',
  'pb-23.s1.item1': 'Is there enough context, without unspoken assumptions?',
  'pb-23.s1.item2': 'Is the desired format explicitly named?',
  'pb-23.s1.item3': 'Are audience and tone appropriately defined?',
  'pb-23.s2.explanation': 'With practice, these checkpoints become habitual and run almost automatically – the time required drops significantly while prompt quality rises.',
  'pb-23.s2.statement': 'Using a personal checklist means you need just as long for every prompt as you did before knowing these principles.',
  'pb-23.title': 'Your Personal Prompt Checklist',
  'pb-24.s0.body': 'Passive phrasings like "A summary should be created" obscure who\'s supposed to act. An active, direct instruction like "Create a summary" is clearer and leaves less room for misinterpretation.',
  'pb-24.s0.title': 'Who Should Do What?',
  'pb-24.s1.explanation': 'The second version is a direct instruction with a clear action and quantity. The first unnecessarily describes the task vaguely and passively.',
  'pb-24.s1.opt0': 'It would be good if a list of advantages could be created.',
  'pb-24.s1.opt1': 'Create a list of five advantages.',
  'pb-24.s1.question': 'Which prompt is phrased more clearly?',
  'pb-24.s2.explanation': 'Politeness doesn\'t depend on active/passive voice (see the lesson on politeness vs. directness). Active phrasings are usually clearer without coming across as impolite.',
  'pb-24.s2.statement': 'Passive phrasings are fundamentally more polite and therefore always the better choice.',
  'pb-24.title': 'Use Active Instead of Passive Phrasing',
  'pb-25.s0.body': 'Phrasings like "a few examples" or "a short list" leave the exact quantity open. A concrete number ("3 examples", "5 points") makes the result directly verifiable – you can immediately see whether the requirement was met.',
  'pb-25.s0.title': '"A Few" Isn\'t a Number',
  'pb-25.s1.blank0': 'exactly 3 advantages',
  'pb-25.s1.blank1': 'many advantages',
  'pb-25.s1.explanation': '"Exactly 3" is a verifiable requirement. "Many" is just as vague as "a few" and doesn\'t solve the underlying problem.',
  'pb-25.s1.prefix': 'Instead of "Name a few advantages", "Name ',
  'pb-25.s1.suffix': '" the more verifiably precise variant.',
  'pb-25.s2.explanation': '"Write a maximum of 100" is incomplete – 100 words? Characters? Sentences? The unit must be explicitly named, otherwise interpretation remains open.',
  'pb-25.s2.statement': 'For units of measurement (e.g. words, minutes, euros), it\'s enough to name just the number – the unit follows automatically.',
  'pb-25.title': 'Specifying Numbers and Units',
  'pb-26.s0.body': 'A question ("What are the advantages of X?") and an instruction ("List the advantages of X") often lead to differently structured answers – questions tend to produce prose, instructions tend to produce the actually desired form.',
  'pb-26.s0.title': 'Two Different Output Shapes',
  'pb-26.s1.explanation': 'The instruction explicitly names both quantity AND format. An open question leaves both up to the model.',
  'pb-26.s1.opt0': 'What are good habits for productivity?',
  'pb-26.s1.opt1': 'List 5 good productivity habits as a numbered list.',
  'pb-26.s1.question': 'You want a clear, numbered list as the result. Which phrasing fits better?',
  'pb-26.s2.explanation': 'Questions are perfectly legitimate, e.g. for exploratory, open-ended topics. For a clearly defined output format, an instruction is usually more reliable – this isn\'t a universal ban.',
  'pb-26.s2.statement': 'Questions are fundamentally worse than instructions and should never be used.',
  'pb-26.title': 'Question vs. Instruction',
  'pb-27.s0.body': 'A model only knows what\'s actually in the prompt (or the conversation so far). It doesn\'t see open browser tabs, earlier unshared conversations, or an image you didn\'t attach. Any silent assumption of "shared knowledge" leads to disappointment.',
  'pb-27.s0.title': 'The Boundaries of Context',
  'pb-27.s1.explanation': 'Separate conversations are typically isolated from each other – the model has no automatic access to earlier conversations that weren\'t provided. Relevant context has to be given again.',
  'pb-27.s1.statement': 'If you explained something in an earlier, separate conversation with the same model, the model automatically remembers it in the current prompt.',
  'pb-27.s2.explanation': 'The model doesn\'t know your specific company style unless you show it concretely. Example texts are the most reliable way to make an implicit concept like "our style" tangible.',
  'pb-27.s2.opt0': 'Just write "in our company\'s style" and assume the model knows your style',
  'pb-27.s2.opt1': 'Include one or two example texts of your actual style directly in the prompt',
  'pb-27.s2.question': 'You want a model to write a text in "your company\'s style". What\'s the most reliable approach?',
  'pb-27.title': 'What the Model Can\'t See',
  'pb-28.s0.body': 'Words like "actually", "kind of", "sort of", or "basically" rarely add substantive precision – they just lengthen the prompt without making the instruction clearer. Removing them makes the core of the task more visible.',
  'pb-28.s0.title': 'Filler Words Cost Clarity',
  'pb-28.s1.blank0': 'Shorten this text." reduce it',
  'pb-28.s1.blank1': 'Can you actually kind of shorten the text?" reduce it',
  'pb-28.s1.explanation': 'Completely removing all filler words doesn\'t change the meaning, but makes the instruction noticeably more direct and shorter.',
  'pb-28.s1.prefix': '"Can you kind of actually sort of help me shorten a text?" can be reduced without loss of meaning to "',
  'pb-28.s1.suffix': '',
  'pb-28.s2.explanation': 'Directness and impoliteness are two different things (see Politeness vs. Directness). A clear prompt without filler words isn\'t automatically phrased unkindly.',
  'pb-28.s2.statement': 'Removing filler words automatically means the prompt seems impolite or too terse.',
  'pb-28.title': 'Spotting Redundant Words',
  'pb-29.s0.body': 'A simple but effective trick: read your prompt as if you had no prior knowledge of the topic at all – the way the model does. Spots where you yourself would stumble or feel unsure what\'s meant are exactly the spots that need refining.',
  'pb-29.s0.title': 'The Perspective-Shift Trick',
  'pb-29.s1.explanation': 'The trick uncovers exactly the gaps that arise when you, as the author, unconsciously assume knowledge of your own that was never explicitly stated in the prompt.',
  'pb-29.s1.opt0': 'Because it reveals where you assumed unspoken knowledge of your own as a given',
  'pb-29.s1.opt1': 'Because it automatically corrects the prompt\'s grammar',
  'pb-29.s1.question': 'Why does the perspective-shift trick work?',
  'pb-29.s2.explanation': 'The trick is a quick mental pre-check, not a substitute for actually testing with a real model – some problems only become visible in the actual result.',
  'pb-29.s2.statement': 'This trick completely replaces the need to actually test a prompt.',
  'pb-29.title': 'Reading Your Own Prompt Aloud',
  'pb-30.s0.body': '"The text should be short" is a preference, not a fixed rule – the model can deviate from it. "The text must not exceed 50 words" is a hard limit. If a requirement truly matters to you, phrase it as a must, not a should.',
  'pb-30.s0.title': 'Distinguishing Soft and Hard Requirements',
  'pb-30.s1.explanation': '"Should" is a soft preference. For a truly critical constraint, a hard, unambiguous phrasing is more reliable.',
  'pb-30.s1.opt0': 'Brand names should be avoided.',
  'pb-30.s1.opt1': 'Under no circumstances mention brand names.',
  'pb-30.s1.question': 'You really want to ensure a response never mentions brand names. Which phrasing is more reliable?',
  'pb-30.s2.explanation': 'Not every requirement is equally important – genuine preferences can perfectly well be phrased as "should". Phrasing everything as a hard must dilutes the effect when it truly matters.',
  'pb-30.s2.statement': 'Every instruction should always be phrased as a hard "must" rule, regardless of how important it actually is.',
  'pb-30.title': '"Should" vs. "Must"',
  'pb-31.s0.body': '"Name the best restaurants" is an absolute but unclear judgment – best by what measure? "Name 5 restaurants with a good price-to-value ratio" uses a concrete, relative quantity with a clear criterion. Concrete number plus criterion beats vague superlatives.',
  'pb-31.s0.title': '"The Best" vs. "5 Good"',
  'pb-31.s1.explanation': '"Most important point" is absolute and subjectively evaluative without a clear criterion. "3 most commonly discussed causes" has both a number and a comprehensible criterion (frequency of discussion).',
  'pb-31.s1.opt0': 'What\'s the most important point about climate change?',
  'pb-31.s1.opt1': 'Name the 3 most commonly discussed causes of climate change.',
  'pb-31.s1.question': 'Which prompt is most likely to deliver a comprehensible, consistent result?',
  'pb-31.s2.explanation': 'Superlatives are fine as long as a clear criterion is provided ("the fastest method by execution time"). Only the superlative without any criterion is problematic.',
  'pb-31.s2.statement': 'Superlatives like "the best" or "the most important" should fundamentally be avoided and must never be used.',
  'pb-31.title': 'Absolute vs. Relative Quantities',
  'pb-32.s0.body': 'If you\'re unsure which of two phrasings works better, you don\'t have to guess – try both and compare the results directly side by side. This is the simplest entry point into systematically improving prompts.',
  'pb-32.s0.title': 'Trying It Out Instead of Guessing',
  'pb-32.s1.explanation': 'If you change several things at once, you won\'t know in the end which change was responsible for the difference. Changing only one variable makes the comparison meaningful.',
  'pb-32.s1.opt0': 'Change only ONE element between the two variants, keep everything else the same',
  'pb-32.s1.opt1': 'Make both variants as different as possible to learn more',
  'pb-32.s1.question': 'What\'s the most important condition for a comparison between two prompt variants to be meaningful?',
  'pb-32.s2.explanation': 'Models can respond slightly differently to the same prompt. A single comparison is a good first indication, but truly reliable conclusions need multiple runs – we\'ll deepen this in the iterative refinement path.',
  'pb-32.s2.statement': 'A single comparison between two variants already delivers a statistically reliable result.',
  'pb-32.title': 'Comparing Two Prompt Variants',
  'pb-33.s0.body': 'You now know precision, the one-task principle, audience, order, hard vs. soft requirements, concrete quantities, and the perspective-shift check. This lesson tests whether you can combine these tools in a new situation.',
  'pb-33.s0.title': 'Second Progress Check',
  'pb-33.s1.explanation': 'Option 2 combines audience (working people without cooking experience), concrete quantity (exactly 3, max. 3 ingredients), format (numbered list), and a hard constraint (no technical terms) – option 1 is vague in every respect.',
  'pb-33.s1.opt0': 'Write something about healthy eating, should be kind of helpful.',
  'pb-33.s1.opt1': 'Create exactly 3 breakfast ideas (max. 3 ingredients each) for working people without cooking experience, as a numbered list, without technical terms.',
  'pb-33.s1.question': 'Which prompt best combines the most principles learned so far?',
  'pb-33.s2.explanation': 'Goal and audience come first because they shape everything else. The perspective-shift check comes before the actual test, to catch obvious gaps beforehand.',
  'pb-33.s2.instruction': 'You want to write a complex prompt. Put these thinking steps into a sensible order.',
  'pb-33.s2.item0': 'Define the core goal and audience',
  'pb-33.s2.item1': 'Add concrete quantities and format',
  'pb-33.s2.item2': 'Read the draft aloud and check for gaps',
  'pb-33.s2.item3': 'Actually test the prompt',
  'pb-33.title': 'Building Blocks of a Solid Prompt',
  'pb-34.s0.body': 'Before writing a prompt, it helps to briefly summarize the task in your own simple words: "I want X so that Y happens." If that\'s hard to do, the task itself isn\'t clear enough yet – and that would show up directly in the prompt.',
  'pb-34.s0.title': 'Understand First, Then Phrase It',
  'pb-34.s1.explanation': 'Difficulty summarizing it yourself usually points to a still-unclear goal – worth clarifying before time goes into wording the prompt.',
  'pb-34.s1.statement': 'If you can\'t summarize a task in one simple sentence, that\'s a warning sign before writing the actual prompt.',
  'pb-34.title': 'Paraphrasing the Task in Your Own Words',
  'pb-35.s0.body': 'Sometimes you just need a clear yes or no, no explanation around it. State that explicitly: "Answer only with \'Yes\' or \'No\'." Without this constraint, you often get a hedging paragraph instead of a clear decision.',
  'pb-35.s0.title': 'Forcing Binary Answers',
  'pb-35.s1.explanation': 'Without the explicit format instruction, models tend to justify their assessment – that\'s often not wrong, but simply not what you wanted in this case.',
  'pb-35.s1.opt0': 'Nothing, the model will understand on its own',
  'pb-35.s1.opt1': '"Answer only with \'correct\' or \'not correct\'."',
  'pb-35.s1.question': 'You just want to know if a sentence is grammatically correct, without a long explanation. What do you add to the prompt?',
  'pb-35.title': 'Prompts for Yes/No Decisions',
  'pb-36.s0.body': 'If you want a process or method explained, explicitly asking for a step-by-step presentation helps ("Explain in numbered steps how..."). Without this instruction, the model often wraps the process into a single prose paragraph that\'s harder to follow.',
  'pb-36.s0.title': 'Processes Instead of Prose',
  'pb-36.s1.blank0': '"in numbered steps"',
  'pb-36.s1.blank1': '"as interestingly as possible"',
  'pb-36.s1.explanation': '"Numbered steps" is a concrete format instruction that leads directly to the desired structure. "As interestingly as possible" affects tone, not structure.',
  'pb-36.s1.prefix': 'To get a guide as a clear structure instead of prose, you add to the prompt ',
  'pb-36.s1.suffix': '.',
  'pb-36.title': 'Requesting Step-by-Step Explanations',
  'pb-37.s0.body': 'Summarizing means making a text shorter while keeping only the core content. Paraphrasing means restating the same content in different words, often at a similar length. If you want it shorter, ask to "summarize", not to "paraphrase".',
  'pb-37.s0.title': 'Two Different Tasks',
  'pb-37.s1.explanation': 'Both terms describe different tasks with different expected lengths. Confusing them often leads to a result that doesn\'t match the actual intent.',
  'pb-37.s1.statement': '"Paraphrase this text" and "Summarize this text" reliably lead to the same result.',
  'pb-37.title': 'Summarizing vs. Paraphrasing',
  'pb-38.s0.body': 'When you send along a longer text for processing (e.g. to summarize), it should be clearly recognizable what\'s the instruction and what\'s the material to be processed. A simple base structure: briefly state the task first, then the text itself, clearly set apart.',
  'pb-38.s0.title': 'What\'s Material, What\'s the Task?',
  'pb-38.s1.explanation': 'Without clear separation, there\'s a risk that phrasings within the material itself get misunderstood as commands – a clear structure prevents this. This technical deepening (e.g. with delimiters) follows in the structure path.',
  'pb-38.s1.opt0': 'The model might mistakenly interpret parts of the material as additional instructions',
  'pb-38.s1.opt1': 'The model fundamentally only reads the first two sentences of a prompt',
  'pb-38.s1.question': 'Why is it problematic to mix instruction and text-to-process without a clear separation?',
  'pb-38.title': 'Separating Input Text and Instruction',
  'pb-39.s0.body': 'Instead of just describing a transformation rule, you can show it with a concrete example pair: "Input: \'good\' → Output: \'excellent\'". The model often recognizes the pattern faster and more reliably from a shown example than from an abstract description.',
  'pb-39.s0.title': 'Showing Instead of Just Describing',
  'pb-39.s1.explanation': 'A shown example makes concretely tangible how much the tone should change – "more formal" alone leaves a lot of room for interpretation of exactly how formal.',
  'pb-39.s1.opt0': 'Just describe it: "Make the sentences more formal."',
  'pb-39.s1.opt1': 'Show an example pair: "\'Hey, that doesn\'t work\' → \'This unfortunately does not meet the requirements.\'"',
  'pb-39.s1.question': 'You want informal sentences translated into formal business language. What works more reliably?',
  'pb-39.title': 'Examples as Input-Output Pairs',
  'pb-40.s0.body': 'Beyond pure word count, you can also control the substantive scope: "just the 3 most important points" instead of an exhaustive listing, or conversely "as complete as possible". This is a different lever than the pure length specification from an earlier lesson.',
  'pb-40.s0.title': 'Depth, Not Just Length',
  'pb-40.s1.blank0': 'substantive scope, not just the word count',
  'pb-40.s1.blank1': 'the spelling of the answer',
  'pb-40.s1.explanation': 'The phrasing limits how many reasons should be named – this is a substantive scope control, independent of the answer\'s pure word count.',
  'pb-40.s1.prefix': '"Name the 3 most important reasons" controls the ',
  'pb-40.s1.suffix': '.',
  'pb-40.title': 'Controlling Response Scope',
  'pb-41.s0.body': 'A brief, critical review before sending pays off: Is every instruction unambiguous? Are there unspoken assumptions? Is the format clear? This habit is the transition from random prompting to systematic work.',
  'pb-41.s0.title': 'The Final Look Before Sending',
  'pb-41.s1.explanation': 'Even short prompts can contain unspoken assumptions. The check only takes a few seconds for short prompts and is still worthwhile.',
  'pb-41.s1.statement': 'A critical review is only worthwhile for very long, complex prompts; for short prompts it\'s a pure waste of time.',
  'pb-41.title': 'Critically Reviewing Your Own Prompts',
  'pb-42.s0.body': 'After so much emphasis on precision and brevity: a prompt can also be too short if it lacks necessary context as a result. "Write something about dogs" is short, but underspecified – what\'s missing here isn\'t brevity, but necessary information.',
  'pb-42.s0.title': 'Brevity Can Also Be a Problem',
  'pb-42.s1.explanation': 'A good prompt is as short as possible, but not shorter than necessary – the completeness of necessary information is the real criterion, not word count alone.',
  'pb-42.s1.opt0': 'By pure word count – shorter is always better',
  'pb-42.s1.opt1': 'By whether all necessary information (goal, context, format) is included, no matter how short that ends up being overall',
  'pb-42.s1.question': 'How do you tell a good short prompt apart from a too-short, underspecified one?',
  'pb-42.title': 'When a Prompt Is Too Short',
  'pb-43.s0.body': 'A model is a powerful tool with real limits – it can be wrong, reproduce outdated information, or miss nuances. Good prompting substantially improves your odds of success, but doesn\'t replace your own critical review of the result.',
  'pb-43.s0.title': 'A Tool, Not an Oracle',
  'pb-43.s1.explanation': 'Good prompting substantially reduces error sources but doesn\'t eliminate them entirely. Critical review of the result remains part of responsible use of the tool.',
  'pb-43.s1.statement': 'A perfectly formulated prompt always guarantees an error-free result.',
  'pb-43.title': 'Realistic Expectations of a Model',
  'pb-44.s0.explanation': '"Cool" is a vague judgment without a criterion, the platform (Instagram? LinkedIn?) strongly affects tone and length, and which product is meant is completely missing.',
  'pb-44.s0.opt0': 'Concrete product/context, target platform (which social media?), and a clear criterion instead of "cool"',
  'pb-44.s0.opt1': 'Nothing, the prompt is already sufficiently clearly phrased',
  'pb-44.s0.question': 'You\'re asked to evaluate a prompt: "Write something cool about our new product, like 2-3 paragraphs, for social media I guess." What\'s missing the most?',
  'pb-44.s1.explanation': 'Context and product first, because they form the foundation. Platform next, because it affects tone and format. Criterion and length are finishing touches at the end.',
  'pb-44.s1.instruction': 'Put the improvement of the example prompt into a sensible editing order.',
  'pb-44.s1.item0': 'Add the concrete product and context',
  'pb-44.s1.item1': 'Name the target platform',
  'pb-44.s1.item2': 'Replace "cool" with a concrete criterion (e.g. "curiosity-inducing")',
  'pb-44.s1.item3': 'Fix the length exactly (e.g. "exactly 2 paragraphs, max. 3 sentences each")',
  'pb-44.title': 'Third Progress Check',
  'pb-45.s0.body': 'This is the grand summary of the entire prompt-basics path. These tasks combine precision, audience, format, order, hard vs. soft requirements, and more – in varying constellations, as you\'ll encounter them in real practice.',
  'pb-45.s0.title': 'Bringing It All Together',
  'pb-45.s1.explanation': 'Before even writing a prompt, you need the missing building blocks: audience/context (brand tone), format (response length), constants (always an apology?). An immediate, general prompt would leave all these gaps open.',
  'pb-45.s1.opt0': 'Immediately write a general prompt: "Answer this customer complaint professionally."',
  'pb-45.s1.opt1': 'Ask follow-up questions: brand tone, typical complaint types, desired response length, whether an apology should always be included',
  'pb-45.s1.question': 'A colleague asks for your help: "I need a prompt that helps me answer customer complaints." What\'s your first step?',
  'pb-45.s2.blank0': 'this task is recurring, with a stable structure but changing content',
  'pb-45.s2.blank1': 'placeholders fundamentally make the model respond faster',
  'pb-45.s2.explanation': 'Answering customer complaints is a recurring task with a stable structure (tone, format stay the same) and changing content (each complaint is different) – exactly the case where a template pays off.',
  'pb-45.s2.prefix': 'After asking for the details, you build a reusable template with placeholders like {{complaint_text}}, because ',
  'pb-45.s2.suffix': '.',
  'pb-45.s3.explanation': 'Even experienced prompt authors benefit from routine checks, especially for more complex or new tasks. Knowledge doesn\'t replace diligence – both complement each other.',
  'pb-45.s3.statement': 'After finishing this path, you\'ll never need a checklist or review again because you now perfectly master the principles.',
  'pb-45.title': 'Big Capstone Project: Your Prompt Toolkit',
};
